24	          rst_i     : in  std_logic;                               -- sync reset
25	          vld_i     : in  std_logic;                               -- strobe in
26	          raz_i     : in  std_logic;                               -- reset  output
27	          dat_i     : in  std_logic_vector(width_g - 1 downto 0);  -- data input
28	          vld_o     : out std_logic;                               -- strobe output
29	          dat_o     : out std_logic_vector(width_g - 1 downto 0);  -- data output
30	          run_dat_o : out std_logic_vector(width_g - 1 downto 0);  -- data output running
31	          run_str_o : out std_logic);                              --
32	end entity;
