35	  signal data_s    : std_logic_vector(width_g - 1 downto 0) := (others => '0');
36	  signal raz_dff_s : std_logic                               := '0';
37	  signal str_s     : std_logic;
38	begin
39	
40	  proc_min_max : process(clk_i)
41	  begin
42	    if rising_edge(clk_i) then
43	      if rst_i = rst_pol_g then
44	        raz_dff_s <= '0';
45	        data_s    <= (others => '0');
46	        dat_o    <= (others => '0');
47	      else
48	        str_s<= vld_i;
49	        raz_dff_s <= raz_i;
50	
51	        if raz_i = '1' and raz_dff_s = '0' then
52	          dat_o <= data_s;
53	          vld_o  <= '1';
54	        else
55	          vld_o <= '0';
56	        end if;
57	
58	        --*** reset value edge detect ***
59	        if raz_i = '1' and raz_dff_s = '0' then
60	          data_s <= dat_i;
61	        else
62	          if vld_i = '1' then
63	            if mode_g = "MIN" and signed_g then
64	              if signed(dat_i) <= signed(data_s) then
65	                data_s <= dat_i;
66	              end if;
67	            elsif mode_g = "MIN" and signed_g = false then
68	              if unsigned(dat_i) <= unsigned(data_s) then
69	                data_s <= dat_i;
70	              end if;
71	            elsif mode_g = "MAX" and signed_g then
72	              if signed(dat_i) >= signed(data_s) then
73	                data_s <= dat_i;
74	              end if;
75	            else
76	              if unsigned(dat_i) >= unsigned(data_s) then
77	                data_s <= dat_i;
78	              end if;
79	            end if;
