1	------------------------------------------------------------------------------
2	--  Copyright (c) 2023 by Paul Scherrer Institute, Switzerland
3	--  All rights reserved.
4	--  Authors: Benoit Stef
5	------------------------------------------------------------------------------
6	
7	------------------------------------------------------------------------------
8	-- Description
9	------------------------------------------------------------------------------
10	-- It's a basic PWM generic that provide std_logic output, user defines few 
11	-- generic parameters and accordingly some command registers allows to produce
12	-- desired output. Rate increase the counter increment to be able to generate 
13	-- two or any integer multiple of pulses within a period with frequency set by
14	-- generics. In addition two comparator (not optimized for speed) allow to
15	-- add delay and bring back to zero the output, settings are set in sample defines
16	-- by strobe freqeuncy generics
17	
18	library ieee;
19	library ieee;
20	use ieee.std_logic_1164.all;
21	use ieee.numeric_std.all;
22	use ieee.math_real.all;
23	use work.psi_common_math_pkg.all;
24	
25	entity psi_common_pwm is
26	  generic(clk_freq_g : natural   := 125E6;  -- clock frequency
27	          str_freq_g : natural   := 100e3;  -- strobe frequency
28	          period_g   : real      := 3.125;  -- signal period
29	          is_sync_g  : boolean   := true;   -- sync paramter with trigger input is True or change on the fly if false
30	          rst_pol_g  : std_logic := '0');   -- reset polarity
31	  port(   clk_i      : in  std_logic;       -- system clock
32	          rst_i      : in  std_logic;       -- system reset
33	          trig_i     : in  std_logic;       -- trigger input, ideally same frequency that period generic
34	          rate_i     : in  std_logic_vector(log2ceil(real(str_freq_g) / period_g) - 1 downto 0);-- rate, increase pulse rate within a period, if set to 2 then 2 pulses
35	          pwm_i      : in  std_logic_vector(log2ceil(real(str_freq_g) / period_g) - 1 downto 0);-- pwm is equivalent to duty cycle but set in sample at str_freq
36	          dly_i      : in  std_logic_vector(log2ceil(real(str_freq_g) / period_g) - 1 downto 0);-- allow delaying pulse start in sample at str_freq 
37	          dat_o      : out std_logic;       -- data output, logic 'active high'    
38	          vld_o      : out std_logic);      -- vld output at str_freq rate
39	end entity;
40	
41	architecture RTL of psi_common_pwm is
42	  constant ratio_c    : natural                       := natural(real(str_freq_g) / period_g);
43	  constant nbit_c     : natural                       := log2ceil(real(str_freq_g) / period_g);
44	  signal cpt_period_s : unsigned(nbit_c downto 0);
45	  signal str_100k_s   : std_logic;
46	  signal cpt_inc_s    : unsigned(nbit_c - 1 downto 0) := (others => '0');
47	  signal trig_dff_s   : std_logic;
48	  signal edge_s       : std_logic;
49	  signal pwm_s        : unsigned(pwm_i'range);
50	  signal dly_s        : unsigned(dly_i'range);
51	  signal pwm_plus_dly_s : unsigned(pwm_i'range);
52	begin
53	
54	  --=================================================================
55	  inst_strobe_100k : entity work.psi_common_strobe_generator
56	    generic map(freq_clock_g  => real(clk_freq_g),
57	                freq_strobe_g => real(str_freq_g),
58	                rst_pol_g     => rst_pol_g)
59	    port map(clk_i  => clk_i,
60	             rst_i  => rst_i,
61	             sync_i => trig_i,
62	             vld_o  => str_100k_s);
63	
64	  proc_cpt : process(clk_i)
65	  begin
66	    if rising_edge(clk_i) then
67	      trig_dff_s <= trig_i;
68	      --*** trig edge detect ***
69	      if trig_i = '1' and trig_dff_s = '0' then
70	        edge_s <= '1';
71	        pwm_s  <= unsigned(pwm_i);
72	        dly_s  <= unsigned(dly_i);
73	      else
74	        edge_s <= '0';
75	      end if;
76	      
77	      --*** compute pwm wit delay signal
78	      pwm_plus_dly_s <= pwm_s + dly_s;
79	
80	      --*** is sync? new ratio ***
81	      if is_sync_g then
82	        if edge_s = '1' then
83	          cpt_inc_s <= unsigned(rate_i(cpt_inc_s'range));
84	        end if;
85	      end if;
86	      --
87	      if not is_sync_g then
88	        cpt_inc_s <= unsigned(rate_i(cpt_inc_s'range));
89	      end if;
90	
91	      --*** super period counter ***
92	      if str_100k_s = '1' then
93	        if cpt_period_s >= ratio_c - cpt_inc_s then
94	          cpt_period_s <= (others => '0');
95	        else
96	          cpt_period_s <= cpt_period_s + cpt_inc_s;
97	        end if;
98	      end if;
99	      vld_o <= str_100k_s;
100	      if str_100k_s = '1' then
101	        if cpt_period_s >= dly_s and cpt_period_s <= pwm_plus_dly_s  and
102	            pwm_s /= to_unsigned(0,pwm_s'length)                     then
103	          dat_o <= '1';
104	        else
105	          dat_o <= '0';
106	        end if;
107	      end if;
108	
109	      -- sync
110	      if (is_sync_g and edge_s = '1') then
111	        cpt_period_s <= (others => '0');
112	      end if;
113	
114	      --*** reset sync ***
115	      if (rst_i = rst_pol_g) then
116	        cpt_period_s <= (others => '0');
117	        cpt_inc_s    <= (others => '0');
118	      end if;
119	
120	    
121	    end if;
122	  end process;
123	
124	end architecture;
125

